1263	// Shared socket (>1 view):
1264	//   - A source already bound by a prior authenticated PROBE routes straight to that peer's
1265	//     view of THIS socket (one lock-free map Load). A frame that does not verify under that
1266	//     peer's psk — a spoofed source it cannot forge the MAC for — is dropped by handleInbound.
1267	//   - An unbound source is trial-decoded against each peer's psk-derived codec (O(peers),
1268	//     bounded by the static peer count). Only an authenticated PROBE establishes a binding
1269	//     (D9/D11: bindings, like remotes, are learned only from authenticated PROBEs), and a
1270	//     PROBE's MAC verifies under EXACTLY ONE psk — so the FIRST psk whose codec yields a PROBE
1271	//     identifies the peer, binds the source, dispatches, and the loop STOPS there. A non-PROBE
1272	//     decode does NOT stop the trial: DATA/PARITY carry no MAC and are forgeable by design, so
1273	//     a genuine PROBE from a later peer can cross-psk-garble into a DATA/PARITY kind under an
1274	//     earlier peer's codec (~0.4%); the loop must therefore `continue` past a non-PROBE decode
1275	//     to give every remaining psk its chance to authenticate a PROBE. A non-PROBE decode
1276	//     carries no binding authority and is dropped either way — a genuine DATA/PARITY from a
1277	//     not-yet-bound source never dispatches or binds until that peer's PROBE binds it, so
1278	//     continuing past it changes nothing for genuine frames. A forged/garbage frame verifies
1279	//     as a PROBE under NO psk, binds nothing, and is dropped cheaply.
1280	func (m *Multipath) demuxInbound(ps *peerPathState, raw []byte, srcAP netip.AddrPort) {
1281		views := ps.views.Load()
1282		if views == nil || len(*views) <= 1 {
1283			m.handleInbound(ps, raw, srcAP)
