1285		}
1286		if bound, ok := m.lookupPeerBySource(srcAP.Addr()); ok {
1287			for _, v := range *views {
1288				if v.peer == bound {
1289					m.handleInbound(v, raw, srcAP)
1290					return
1291				}
1292			}
1293			return // the bound peer holds no view of this socket (removed): drop
1294		}
1295		for _, v := range *views {
1296			fr, err := v.codec.Decode(raw)
1297			if err != nil {
1298				continue // not this peer's psk — try the next
1299			}
