	t.Helper()
	privRaw, _ := genX25519(t)

	var peers strings.Builder
	for i := 0; i < numPeers; i++ {
		_, pubRaw := genX25519(t)
		fmt.Fprintf(&peers, "\n[[wireguard.peers]]\npublic_key = \"%s\"\nallowed_ips = [\"10.0.%d.0/24\"]\n",
